Click = () => emit(\'click\', { x: 1 })\n    return () => h(\'button\', { onClick: handleClick }, slots.default ? slots.default() : props.label)\n  }\n})\n```\n\nLive Coding Task:\n\nRun the starter code, then complete the TODOs.\n\n{{starter:\n// simulate component default props and user props const defaultProps = { title: \'Default Title\', size: \'md\' }; const userProps = { title: \'Hello\' }; const merged = Object.assign({}, defaultProps, userProps); console.log(merged.title.toLowerCase());\n}}\n\n{{answer: hello}}','https://www.youtube.com/watch?v=ZkO8_3k8Kq8',4,15,1,'2026-05-16 17:26:10','2026-05-22 19:32:37',NULL,'javascript'),('2f2bc720-5133-11f1-9abe-6c02e0d26821','2f27500d-5133-11f1-9abe-6c02e0d26821','Build and publish a typed UI component library','code_example',1,'Package, type, and publish a reusable UI component library in TypeScript: create distributable bundles, generate and export accurate .d.ts typings, and configure package.json for interoperable named and default exports. Why: consumers get IDE autocompletion, safe upgrades, and minimal runtime friction. Pitfall: mismatched export shapes or missing declaration files break consumers ظـزظــظ꓂㐀Ⰶ숥ظ꓂㐀樆㐥 瀀愀礀 愀琀琀攀渀琀椀漀渀 琀漀 琀猀挀漀渀昀椀最 搀攀挀氀愀爀愀琀椀漀渀 猀攀琀琀椀渀最猀Ⰰ 戀甀渀搀氀攀爀 漀甀琀瀀甀琀Ⰰ 愀渀搀 攀砀瀀漀爀琀 猀甀爀昀愀挀攀⸀✀Ⰰ✀䰀攀猀猀漀渀㨀 䈀甀椀氀搀 愀渀搀 瀀甀戀氀椀猀栀 愀 琀礀瀀攀搀 唀䤀 挀漀洀瀀漀渀攀渀琀 氀椀戀爀愀爀礀尀渀尀渀㸀 一漀琀攀㨀 䰀椀瘀攀 䨀愀瘀愀匀挀爀椀瀀琀 攀搀椀琀漀爀 爀甀渀猀 椀渀 琀栀攀 戀爀漀眀猀攀爀⸀ 䄀瘀漀椀搀 怀爀攀焀甀椀爀攀怀Ⰰ 怀瀀爀漀挀攀猀猀怀Ⰰ 愀渀搀 猀攀爀瘀攀爀 猀琀愀爀琀甀瀀 挀漀搀攀 栀攀爀攀⸀尀渀尀渀唀猀攀昀甀氀 刀攀猀漀甀爀挀攀猀㨀尀渀尀渀ⴀ 栀琀琀瀀猀㨀⼀⼀渀漀搀攀樀猀⸀漀爀最⼀愀瀀椀⼀瀀愀挀欀愀最攀猀⸀栀琀洀氀尀渀尀渀笀笀瘀椀搀攀漀㨀 栀琀琀瀀猀㨀⼀⼀眀眀眀⸀礀漀甀琀甀戀攀⸀挀漀洀⼀眀愀琀挀栀㼀瘀㴀儀䠀唀琀最㘀栀儀䨀㘀夀紀紀尀渀尀渀䔀砀愀洀瀀氀攀㨀尀渀尀渀怀怀怀挀漀搀攀尀渀攀砀瀀漀爀琀 琀礀瀀攀 䈀甀琀琀漀渀倀爀漀瀀猀 㴀 笀尀渀  氀愀戀攀氀㼀㨀 猀琀爀椀渀最㬀尀渀  漀渀䌀氀椀挀欀㼀㨀 ⠀⤀ 㴀㸀 瘀漀椀搀㬀尀渀紀㬀尀渀尀渀攀砀瀀漀爀琀 昀甀渀挀琀椀漀渀 䈀甀琀琀漀渀⠀瀀爀漀瀀猀㨀 䈀甀琀琀漀渀倀爀漀瀀猀⤀ 笀尀渀  爀攀琀甀爀渀 㰀戀甀琀琀漀渀 漀渀䌀氀椀挀欀㴀笀瀀爀漀瀀猀⸀漀渀䌀氀椀挀欀紀㸀笀瀀爀漀瀀猀⸀氀愀戀攀氀 㼀㼀 尀✀漀欀尀✀紀㰀⼀戀甀琀琀漀渀㸀㬀尀渀紀尀渀尀渀攀砀瀀漀爀琀 搀攀昀愀甀氀琀 䈀甀琀琀漀渀㬀尀渀怀怀怀尀渀尀渀䰀椀瘀攀 䌀漀搀椀渀最 吀愀猀欀㨀尀渀尀渀刀甀渀 琀栀攀 猀琀愀爀琀攀爀 挀漀搀攀Ⰰ 琀栀攀渀 挀漀洀瀀氀攀琀攀 琀栀攀 吀伀䐀伀猀⸀尀渀尀渀笀笀猀琀愀爀琀攀爀㨀尀渀⼀⼀ 猀椀洀甀氀愀琀攀 愀 洀椀渀椀洀愀氀 挀漀渀猀甀洀攀爀 甀猀椀渀最 琀栀攀 瀀甀戀氀椀猀栀攀搀 挀漀洀瀀漀渀攀渀琀 氀椀戀爀愀爀礀 昀甀渀挀琀椀漀渀 䈀甀琀琀漀渀⠀瀀爀漀瀀猀⤀