洀瀀椀氀攀 琀椀洀攀⸀ 倀椀琀昀愀氀氀㨀 漀瘀攀爀ⴀ最攀渀攀爀愀氀椀稀椀渀最 琀礀瀀攀猀 挀愀渀 洀愀欀攀 䄀倀䤀猀 栀愀爀搀 琀漀 爀攀愀搀 愀渀搀 挀愀甀猀攀 椀渀昀攀爀攀渀挀攀 琀漀 搀攀最爀愀搀攀 㠀䀆㈆㠆䀆䀆㠆숆¤ش┬胂㠀숆¤ش╪ش prefer constrained generics and clear mapped keys.','Lesson: Design reusable generics, mapped, and conditional types for UI patterns\n\n> Note: Live JavaScript editor runs in the browser. Avoid `require`, `process`, and server startup code here.\n\nUseful Resources:\n\n- https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Object\n\n{{video: https://www.youtube.com/watch?v=ahCwqrYpIuM}}\n\nExample:\n\n```code\ntype ComponentNames = \'button\' | \'input\' | \'card\';\n\n// generic prop wrapper for any component shape\ntype WithProps<T> = {\n  [K in keyof T]: { props: T[K] }\n};\n\n// mapped type turning all fields optional for edit forms\ntype PartialFields<T> = {\n  [K in keyof T]?: T[K]\n};\n\n// conditional type: if field is array return array item, else keep type\ntype UnwrapArray<T> = T extends (infer U)[] ? U : T;\n\n// Usage examples\ntype UIRegistry = WithProps<Record<ComponentNames, {}>>;\ntype EditableState = PartialFields<{ title: string; tags: string[] }>;\ntype TagItem = UnwrapArray<EditableState[\'tags\']>; // string\n```\n\nLive Coding Task:\n\nRun the starter code, then complete the TODOs.\n\n{{starter:\n// list of UI component keys to map at runtime const components = [\"button\", \"input\", \"card\"]; // simple runtime mapping utility that creates a props bag function mapToProps(list) { return list.map(name => ({ name, props: {} })); } const mapped = mapToProps(components); // runtime signal used for the lesson\'s quick live check console.log(\"generics ready\");\n}}\n\n{{answer: generics ready}}','https://www.youtube.com/watch?v=ahCwqrYpIuM',1,15,1,'2026-05-16 17:26:10','2026-05-22 19:32:47',NULL,'javascript'),('2f332530-5133-11f1-9abe-6c02e0d26821','2f30ad4f-5133-11f1-9abe-6c02e0d26821','Apply type guards, branded types, and runtime validation for safety','code_example',1,'Learn to combine TypeScript user-defined type guards, branded types, and runtime validators to ensure safety across compile-time and runtime. This lesson explains why type guards clarify narrow types, branded types prevent accidental mixing of identifiers, and runtime validation handles untrusted input. Youظـزظــظ꓂㐀Ⰶ숥ظـز╪زll see a practical pattern and a common pitfall: relying on compile-time types without runtime checks, which leaves apps vulnerable to malformed data.','Lesson: Apply type guards, branded types, and runtime validation for safety\n\n> Note: Live JavaScript editor runs in the browser. Avoid `require`, `process`, and server startup code here.\n\nUseful Resources:\n\n- https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Symbol\n\n- https://nodejs.org/api/assert.html\n\nExample:\n\n```code\n// TypeScript: branded id and user-defined type guard\ntype UserId = string & { readonly __brand: unique symbol };\n\nfunction brandUserId(id: string): UserId {\n  return id as UserId;\n}\n\ntype User = { id: UserId; name: string };\n\nfunction isUser(obj: any): obj is User {\n  return obj && typeof obj.name === \'string\' && typeof obj.id === \'string\';\n}\n\n// usage: guard first, then brand for downstream safety\nconst maybe = { id: \'user-1\', name: \'alice\' };\nif (isUser(maybe)) {\n  const id = brandUserId(maybe.id);\n}\n```\n\nLive Coding Task:\n\nRun the starter code, then complete the TODOs.\n\n{{starter:\n// runtime validator: checks shape and id format function isUser(obj) { return obj && typeof obj.id === \'string\' && typeof obj.name === \'string\' && /^[a-z0-9-]+$/.test(obj.id); } // runtime \"brand\" using a symbol to mark a value as a user id const USER_BRAND = Symbol(\'userId\'); function brandId(id) { return { value: id, [USER_BRAND]: true }; } function isBrandedId(v) { return v && v[USER_BRAND] === true; } // test samples const good = { id: \'user-123\', name: \'alice\' }; const bad = { id: 123, name: \'bob\' }; // validate and log if (isUser(good) && isBrandedId(brandId(good.id))) { console.log(\'valid user\'); } else { console.log(\'invalid user\'); } if (isUser(bad)) { console.log(\'valid user\'); } else { console.log(\'invalid user\'); }\n}}\n\n{{answer: valid user invalid user}}',NULL,2,15,1,'2026-05-16 17:26:10','2026-05-22 19:32:47',NULL,'javascript'),('2f3397c4-5133-11f1-9abe-6c02e0d26821','2f30ad4f-5133-11f1-9abe-6c02e0d26821','Write unit and integration tests for TypeScript web apps with Jest and testing-library','code_example',1,'Write type-aware unit and integration tests for TypeScript web apps using Jest and testing-library. This lesson shows how to test functions, DOM interactions, and components with type safety, why tests catch regressions early and enforce contracts, and how to avoid common pitfalls like brittle selectors, async timing issues, and over-mocking. Includes a runnable starter that simulates test assertions and a Jest/testing-library example for migrating to a real test suite.','Lesson: Write unit and integration tests for TypeScript web apps with Jest and testing-library\n\n> Note: Live JavaScript editor runs in the browser. Avoid `require`, `process`, and server startup code here.\n\nUseful Resources:\n\n- https://developer.mozilla.org/en-US/docs/Web/API/Document/createElement\n\n- https://developer.mozilla.org/en-US/docs/Web/API/Event\n\n{{video: https://www.youtube.com/watch?v=7r4xVDI2vho}}\n\nExample:\n\n```code\n// Example TypeScript + Jest + testing-library test (conceptual)\nimport { render, fireEvent } from \'@testing-library/react\';\nimport React from \'react\';\nimport Counter from \'./Counter\';\n\ntest(\'counter increments when button is clicked\', () => {\n  const { getByRole, getByText } = render(<Counter />);\n  const button = getByRole(\'button\', { name: /increment/i });\n  fireEvent.click(button);\n  expect(getByText(\'1\')).toBeInTheDocument();\n});\n```\n\nLive Coding Task:\n\nRun the starter code, then complete the TODOs.\n\n{{starter:\n// simple unit function function add(a, b) { return a + b; } // tiny DOM \"component\" factory that can be integration-tested function createCounter() { const container = document.createElement(\'div\'); const btn = document.createElement(\'button\'); const span = document.createElement(\'span\'); let count = 0; span.textContent = \'0\'; btn.addEventListener(\'click\', function() { count += 1; span.textContent = String(count); }); container.appendChild(btn); container.appendChild(span); return { container, btn, span }; } // minimal assertion helper to simulate test runner behavior function assertEqual(actual, expected, message) { if (actual !== expected) { throw new Error(message || `expected ${expected} but got ${actual}`); } } // run a couple of tests and report a concise result try { // unit test: pure function assertEqual(add(2, 3), 5, \'add should sum numbers\'); // integration-style test: DOM interaction const { btn, span } = createCounter(); btn.click(); btn.click(); assertEqual(span.textContent, \'2\', \'counter should increment twice\'); console.log(\'tests passed\'); } catch (e) { console.log(\'tests failed\'); }\n}}\n\n{{answer: tests passed}}','https://www.youtube.com/watch?v=7r4xVDI2vho',3,15,1,'2026-05-16 17:26:10','2026-05-22 19:32:47',NULL,'javascript'),('2f340732-5133-11f1-9abe-6c02e0d26821','2f30ad4f-5133-11f1-9abe-6c02e0d26821','Optimize bundle size and performance with tree-shaking and code splitting','code_example',1,'Show how to configure TypeScript-aware bundlers and structure imports so unused code is removed (tree-shaking) and large features are loaded on demand (code splitting). Learn practical import patterns, bundler flags, and runtime dynamic import strategies to reduce initial payloads and improve perceived performance. Watch for pitfalls: non-pure side-effects, default-export misuse, and improper module formats that prevent tree-shaking.','Lesson: Optimize bundle size and performance with tree-shaking and code splitting\n\n> Note: Live JavaScript editor runs in the browser. Avoid `require`, `process`, and server startup code here.\n\nUseful Resources:\n\n- https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Statements/import#dynamic_imports\n\n{{video: https://www.youtube.com/watch?v=8kNnU7bYw6I}}\n\nExample:\n\n```code\n// math.ts - prefer named exports so bundlers can tree-shake\nexport function add(a: number, b: number) {\n  return a + b;\n}\n\nexport function heavyCompute() {\n  // large implementation kept in its own module\n  return Array.from({ length: 1e6 }).reduce((s, _, i) => s + i, 0);\n}\n\n// main.ts - keep hot paths small, dynamically import heavy work\nimport { add } from \'./math\';\nconsole.log(add(2, 3));\n\nasync function onDemandCompute() {\n  const { heavyCompute } = await import(\'./math\');\n  console.log(heavyCompute());\n}\n```\n\nLive Coding Task:\n\nRun the starter code, then complete the TODOs.\n\n{{starter:\n// simulate app initialization console.log(\'app initialized\'); // a small, always-included feature function lightFeature() { console.log(\'light feature executed\'); } // simulate a lazily-loaded heavy feature represented as a code string function loadHeavyFeature() { const code = ` function heavyFeature() { console.log(\'heavy feature executed\'); } heavyFeature(); `; // evaluate only when needed to simulate a code-split bundle new Function(code)(); } // only use the light feature during normal startup lightFeature(); // heavy feature is available but not invoked unless explicitly requested // Uncomment to simulate user-driven dynamic load // loadHeavyFeature();\n}}\n\n{{answer: app initialized light feature executed}}','https://www.youtube.com/watch?v=8kNnU7bYw6I',4,15,1,'2026-05-16 17:26:10','2026-05-22 19:32:47',NULL,'javascript'),('2f346f1d-5133-11f1-9abe-6c02e0d26821','2f30ad4f-5133-11f1-9abe-6c02e0d26821','Migrate an existing JavaScript web app to TypeScript incrementally and deploy','code_example',1,'Plan and execute a staged migration from JavaScript to 