 console.log(\'static block ran\'); return null; })(); name = \'unnamed\'; _instanceInit = (() => { console.log(\'instance init block ran\'); return true; })(); constructor(name) { // disambiguate parameter name from field using this this.name = name; Person.created += 1; console.log(\'constructor ran for \' + this.name); } } console.log(\'created before instantiation \' + Person.created); const p1 = new Person(\'alice\'); console.log(\'created after first \' + Person.created); const p2 = new Person(\'bob\'); console.log(\'created after second \' + Person.created); console.log(\'first name \' + p1.name); console.log(\'second name \' + p2.name);\n}}\n\n{{answer: static block ran created before instantiation 1 instance init block ran constructor ran for alice created after first 2 instance init block ran constructor ran for bob created after second 3 first name alice second name bob}}','https://www.youtube.com/watch?v=5cm7n18Y3vQ',2,15,0,'2026-05-15 19:38:04','2026-05-15 19:38:04',NULL,'javascript'),('72578df1-507c-11f1-9abe-6c02e0d26821','72561198-507c-11f1-9abe-6c02e0d26821','Apply encapsulation with access modifiers and accessors','code_example',1,'Show how to apply encapsulation in Java using access modifiers (private, public, protected) and accessors (getters/setters). Learn why restricting direct field access prevents invalid state and preserves invariants, and implement validation inside setters. Common pitfall: exposing mutable internal objects or omitting validationظـزظــظ꓂㐀Ⰶ숥ظ꓂㐀樆㐥猆琀椀氀氀 戀爀攀愀欀猀 攀渀挀愀瀀猀甀氀愀琀椀漀渀⸀ 吀栀椀猀 氀攀猀猀漀渀 瀀爀愀挀琀椀挀攀猀 猀愀昀攀 最攀琀琀攀爀猀⼀猀攀琀琀攀爀猀 瀀愀琀琀攀爀渀猀 愀渀搀 搀攀洀漀渀猀琀爀愀琀攀猀 爀攀瀀氀愀挀椀渀最 搀椀爀攀挀琀 昀椀攀氀搀 愀挀挀攀猀猀 眀椀琀栀 挀漀渀琀爀漀氀氀攀搀 洀攀琀栀漀搀猀 昀漀爀 爀漀戀甀猀琀 漀戀樀攀挀琀 猀琀愀琀攀 洀愀渀愀最攀洀攀渀琀⸀✀Ⰰ✀䰀攀猀猀漀渀㨀 䄀瀀瀀氀礀 攀渀挀愀瀀猀甀氀愀琀椀漀渀 眀椀琀栀 愀挀挀攀猀猀 洀漀搀椀昀椀攀爀猀 愀渀搀 愀挀挀攀猀猀漀爀猀尀渀尀渀㸀 一漀琀攀㨀 䰀椀瘀攀 䨀愀瘀愀匀挀爀椀瀀琀 攀搀椀琀漀爀 爀甀渀猀 椀渀 琀栀攀 戀爀漀眀猀攀爀⸀ 䄀瘀漀椀搀 怀爀攀焀甀椀爀攀怀Ⰰ 怀瀀爀漀挀攀猀猀怀Ⰰ 愀渀搀 猀攀爀瘀攀爀 猀琀愀爀琀甀瀀 挀漀搀攀 栀攀爀攀⸀尀渀尀渀唀猀攀昀甀氀 刀攀猀漀甀爀挀攀猀㨀尀渀尀渀ⴀ 栀琀琀瀀猀㨀⼀⼀搀攀瘀攀氀漀瀀攀爀⸀洀漀稀椀氀氀愀⸀漀爀最⼀攀渀ⴀ唀匀⼀搀漀挀猀⼀圀攀戀⼀䨀愀瘀愀匀挀爀椀瀀琀⼀刀攀昀攀爀攀渀挀攀⼀䘀甀渀挀琀椀漀渀猀⼀最攀琀尀渀尀渀笀笀瘀椀搀攀漀㨀 栀琀