ay = \'flex\'; container.style.flexWrap = \'wrap\'; for (let i = 1; i <= 3; i++) { const item = document.createElement(\'div\'); item.textContent = \'Item \' + i; item.style.padding = \'8px\'; item.style.border = \'1px solid #666\'; container.appendChild(item); } document.body.appendChild(container); console.log(\'flex items 3\');\n}}\n\n{{answer: flex items 3}}','https://www.youtube.com/watch?v=JJSoEo8JSnc',1,12,0,'2026-05-15 20:22:01','2026-05-15 20:22:01',NULL,'javascript'),('95f47087-5082-11f1-9abe-6c02e0d26821','95f4152d-5082-11f1-9abe-6c02e0d26821','Create grid-based layouts with CSS Grid','code_example',1,'Learn to build two-dimensional layouts with CSS Grid: define grid tracks, named areas, grid-template syntax, and how implicit grids form. This lesson shows when to use template areas versus explicit tracks, how to size and align tracks, and responsive techniques with media queries and repeat(). Watch out for overly complex area maps and unexpected implicit rows/columnsظـزظــظ꓂㐀Ⰶ숥ظ꓂㐀樆㐥理攀猀琀 愀挀爀漀猀猀 戀爀攀愀欀瀀漀椀渀琀猀⸀✀Ⰰ✀䰀攀猀猀漀渀㨀 䌀爀攀愀琀攀 最爀椀搀ⴀ戀愀猀攀搀 氀愀礀漀甀琀猀 眀椀琀栀 䌀匀匀 䜀爀椀搀尀渀尀渀㸀 一漀琀攀㨀 䰀椀瘀攀 䨀愀瘀愀匀挀爀椀瀀琀 攀搀椀琀漀爀 爀甀渀猀 椀渀 琀栀攀 戀爀漀眀猀攀爀⸀ 䄀瘀漀椀搀 怀爀攀焀甀椀爀攀怀Ⰰ 怀瀀爀漀挀攀猀猀怀Ⰰ 愀渀搀 猀攀爀瘀攀爀 猀琀愀爀琀甀瀀 挀漀搀攀 栀攀爀攀⸀尀渀尀渀唀猀攀昀甀氀 刀攀猀漀甀爀挀攀猀㨀尀渀尀渀ⴀ 栀琀琀瀀猀㨀⼀⼀搀攀瘀攀氀漀瀀攀爀⸀洀漀稀椀氀氀愀⸀漀爀最⼀攀渀ⴀ唀匀⼀搀漀挀猀⼀圀攀戀⼀䌀匀匀⼀䌀匀匀开䜀爀椀搀开䰀愀礀漀甀琀尀渀尀渀ⴀ 栀琀琀瀀猀㨀⼀⼀搀攀瘀攀氀漀瀀攀爀⸀洀漀稀椀氀氀愀⸀漀爀最⼀攀渀ⴀ唀匀⼀搀漀挀猀⼀圀攀戀⼀䌀匀匀⼀最爀椀搀ⴀ琀攀洀瀀氀愀琀攀ⴀ愀爀攀愀猀尀渀尀渀ⴀ 栀琀琀瀀猀㨀⼀⼀搀攀瘀攀氀漀瀀攀爀⸀洀漀稀椀氀氀愀⸀漀爀最⼀攀渀ⴀ唀匀⼀搀漀挀猀⼀圀攀戀⼀䌀匀匀⼀最爀椀搀ⴀ愀甀琀漀ⴀ昀氀漀眀尀渀尀渀笀笀瘀椀搀攀漀㨀 栀琀琀瀀猀㨀⼀⼀眀眀眀⸀礀漀甀琀甀戀攀⸀挀漀洀⼀眀愀琀挀栀㼀瘀㴀㜀欀嘀攀䌀焀儀䌀砀氀欀紀紀尀渀尀渀䔀砀愀洀瀀氀攀㨀尀渀尀渀怀怀怀挀漀搀攀尀渀㰀℀ⴀⴀ 栀琀洀氀 ⴀⴀ㸀尀渀㰀搀椀瘀 挀氀愀猀猀㴀尀∀氀愀礀漀甀琀尀∀㸀尀渀  㰀栀攀愀搀攀爀㸀䠀攀愀搀攀爀㰀⼀栀攀愀搀攀爀㸀尀渀  㰀洀愀椀渀㸀䴀愀椀渀㰀⼀洀愀椀渀㸀尀渀  㰀愀猀椀搀攀㸀匀椀搀攀戀愀爀㰀⼀愀猀椀搀攀㸀尀渀  㰀昀漀漀琀攀爀㸀䘀漀漀琀攀爀㰀⼀昀漀漀琀攀爀㸀尀渀㰀⼀搀椀瘀㸀尀渀尀渀⼀⨀ 挀猀猀 ⨀⼀尀渀⸀氀愀礀漀甀琀 笀尀渀  搀椀猀瀀氀愀礀㨀 最爀椀搀㬀尀渀  最爀椀搀ⴀ琀攀洀瀀氀愀琀攀ⴀ愀爀攀愀猀㨀尀渀    尀∀栀搀 栀搀尀∀尀渀    尀∀洀渀 愀猀尀∀尀渀    尀∀昀琀 昀琀尀∀㬀尀渀  最愀瀀㨀 ㄀㘀瀀砀㬀尀渀紀尀渀怀怀怀尀渀尀渀䰀椀瘀攀 䌀漀搀椀渀最 吀愀猀欀㨀尀渀尀渀刀甀渀 琀栀攀 猀琀愀爀琀攀爀 挀漀搀攀Ⰰ 琀栀攀渀 挀漀洀瀀氀攀琀攀 琀栀攀 吀伀䐀伀猀⸀尀渀尀渀笀笀猀琀愀爀琀攀爀㨀尀渀⼀⼀ 挀爀攀愀琀攀 愀 猀椀洀瀀氀攀 最爀椀搀 挀漀渀琀愀椀渀攀爀 愀渀搀 昀漀甀爀 椀琀攀洀猀 挀漀渀猀琀 挀漀渀琀愀椀渀攀爀 㴀 搀漀挀甀洀攀渀琀⸀挀爀攀愀琀攀䔀氀攀洀攀渀琀⠀尀✀搀椀瘀尀✀⤀㬀 挀漀渀琀愀椀渀攀爀⸀挀氀愀猀猀一愀洀攀 