INSERT INTO `module` VALUES ('1beb3952-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Foundations of Databases & SQL','Introduce core database concepts, installation, and basic interactions with a relational DBMS.',1,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1befaa6b-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Data Modeling and Schema Design','Teach entity-relationship modeling, normalization, and translating models into SQL schema.',2,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bf2eec0-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Querying Single Tables with SQL','Cover SELECT basics, filtering, sorting, expressions, and common functions on single-table queries.',3,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bf75341-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Aggregation, Grouping, and Advanced Aggregates','Teach grouping, HAVING, window functions, and advanced multi-level aggregation techniques.',4,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bfa0ae5-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Joins, Subqueries, and Set Operations','Explain how to combine data across tables using joins, subqueries, and set operators with performance considerations.',5,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bfd52e9-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Data Modification, Transactions, and Concurrency','Teach safe data modification, transactional control, isolation, locking, and upsert patterns.',6,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bffe50a-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Indexing, Performance Tuning, and Scaling','Focus on indexing strategies, query analysis, partitioning, and other performance-improving techniques.',7,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1c0259a6-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Advanced SQL Features and Specialized Data Types','Cover JSON/JSONB, arrays, composite types, full-text search, and writing database-side functions.',8,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1c0561e7-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Security, Operations, and Capstone Project','Teach security best practices, backup/replication, auditing, and apply everything in a practical capstone schema and query set.',9,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1f4967f9-4fbe-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Introduction to Backend Development','This chapter explains what backend development is, how the internet works behind the scenes, and why Node.js became one of the most popular backend technologies.',1,'2026-05-14 20:55:41','2026-05-14 20:55:41'),('2b4f1c0b-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Node.js Fundamentals','In this chapter, students will master the core foundations of Node.js. They will learn about the CommonJS module system, how to create and export modules, and explore important built-in modules such as fs, path, os, and events. This chapter builds the essential skills needed to work effectively with Node.js before moving into more advanced topics.',2,'2026-05-14 21:38:58','2026-05-14 21:38:58'),('2f1e8078-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','TypeScript Essentials for the Web','Core TypeScript language features and compiler options applied to typical web development tasks.',1,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f23c7bf-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','Tooling, Build, and Runtime Integration','Configure build tools, bundlers, and runtime integration to compile, lint, and ship TypeScript web applications.',2,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f27500d-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','TypeScript with Modern Frontend Frameworks','Apply TypeScript patte